  ('judicial-cbdcc9ff-moex-00015', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '富二代甲喜歡混夜店，見貌美女子便搭訕喝酒，某日見 A獨自一人，便
灌 A不同種類的酒，趁 A不勝酒力昏睡時，便攙扶其至汽車旅館對其性
交，另架設手機錄下 A女被性交的畫面及裸睡樣子。第二天甲食髓知味，
又到夜店認識 B，酒後雙方合意至汽車旅館拍攝性愛照片。數週後甲的
手機故障，至乙開設的手機行修理，乙見手機內的性愛照片及錄影精彩，
遂上傳至其臉書供人觀覽炫耀。又因為乙女友 C不久前與其分手，乙心
中憤憤不平，便利用其熟稔資訊技術，將 C的臉與手上性愛照片中女子
的臉合成，製作C的裸照，再傳給 C告訴她，如果不與乙重修舊好，將
傳送到 C所屬公司及家人。請問甲、乙的行為如何論處？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "9f777757f90a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00016', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '警察甲接到商家來電，有位女子乙因喝酒在其店內大聲叫囂、不願離開，
遂到場處理。因乙情緒失控，酒醉而有哭泣不止、拍桌及對甲高聲大叫，
甲無法阻止，見乙拿起椅子，誤以為乙要對其攻擊，情急之下對乙數次
噴灑辣椒水並擊打其頭部，造成乙眼睛無法睜開，因而跌倒受傷。事實
上乙拿椅子只不過是累了想坐下來。經查依「警察人員使用防護型應勤
裝備注意要點」第 3 點規定，警察人員於依法執行職務遭受強暴、脅迫、
抗拒或其他事實需要，除情況急迫外，於相對人經口頭警告仍不聽從時，
始得使用辣椒水。使用時並應依該要點第 4點之規定，考量地形及地物
之狀況，避免造成相對人其他傷害；使用原因已消滅，應立即停止使用。
請問甲的行為是否成立犯罪？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "9f777757f90a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00017', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '甲涉嫌基於意圖營利之犯意，以新臺幣 3,000 元，販賣第一級毒品海洛
因給乙，經檢察官依法向法院聲請搜索票後，於甲之住處扣得第一級毒
品海洛因及前揭買賣毒品之款項，檢察官以甲涉犯上開罪嫌重大、符合
羈押事由及有羈押之必要性，依法聲請法院羈押獲准，嗣檢察官於蒐證
完畢後，就上開案件提起公訴而經法院進行審理。試問：何謂「嚴格之
證明」、「自由之證明」？請說明於刑事程序中，何種事項須經「嚴格之
證明」、何種事項僅以「自由之證明」即可？並請就上開案件中，關於認
定「搜索」、「羈押」及「甲有販賣第一級毒品」等事實，論述是否需要
經「嚴格之證明」？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "9f777757f90a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00018', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '檢察官偵辦甲涉犯詐欺取財罪及一般洗錢罪之案件，先就詐欺取財罪部
分向法院提起公訴，經該法院審核該案卷證資料後，認為已起訴之詐欺
取財罪部分與未起訴之一般洗錢罪部分具有「想像競合犯」裁判上一罪
之關係。請論述檢察官就本案之詐欺取財罪部分起訴，效力是否及於一
般洗錢罪部分？依目前實務之作法，檢察官就該一般洗錢罪部分，通常
係以如何之方式請求法院併予審理？得否就一般洗錢罪部分另行起
訴？倘檢察官就一般洗錢罪部分又向同一法院提起公訴，法院對於該另
行起訴之一般洗錢罪部分，應為如何之處理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "9f777757f90a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00019', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '近年來機關常將公有財產委託廠商經營管理，因此出現政府採購法與促
進民間參與公共建設之適用問題。試論在上述委託經營管理情況下，政
府採購法之適用情形，並分別就各情形舉例說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "397269db592b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00020', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '資訊安全為當前國家安全之重大課題。試論政府採購法對辦理涉及國家
安全採購之相關規定、這些規定對適用政府採購協定（Agreement on
GovernmentProcurement，GPA）的影響，以及陸資廠商之分類與認定。
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "397269db592b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00021', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '政府採購法施行細則第 99條規定：「機關辦理採購有部分先行使用之必
要或已履約之部分有減損滅失之虞者，應先就該部分辦理驗收或分段查
驗供驗收之用，並得就該部分支付價金及起算保固期間。」惟若採購機
關拒絕先行部分驗收即先行使用，試論廠商可循何種法規提出爭議處
理？又在該等爭議處理過程中可能出現「強制仲裁」，試說明強制仲裁之
前提，以及機關規避強制仲裁之可能性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "397269db592b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL)
